export const EditPunchBody = zod.object({
  clockIn: zod.string().nullish(),
  clockOut: zod.string().nullish(),
});

export const EditPunchResponse = zod.object({
  id: zod.number(),
  weekStart: zod.string(),
  kfiId: zod.string(),
  customer: zod.string().nullish(),
  source: zod.enum(["Driver", "Customer"]),
  date: zod.string(),
  clockIn: zod.string(),
  clockOut: zod.string(),
  hours: zod.number(),
  payType: zod.string().nullish(),
  dispTz: zod.string(),
  isManual: zod.boolean(),
  edited: zod.boolean().optional(),
  createdByEmail: zod.string().nullish(),
  updatedByEmail: zod.string().nullish(),
  updatedAt: zod.coerce.date().nullish(),
});

/**
 * @summary Delete a punch (manual or imported)
 */
export const DeletePunchParams = zod.object({
  id: zod.coerce.number(),
});

/**
 * @summary Toggle the "reviewed" state for a driver in a week
 */
export const setReviewedPathWeekStartRegExp = new RegExp(
  "^\\d{4}-\\d{2}-\\d{2}$",
);

export const SetReviewedParams = zod.object({
  weekStart: zod.coerce
    .string()
    .regex(setReviewedPathWeekStartRegExp)
    .describe("Week start date (Monday) in YYYY-MM-DD"),
  kfiId: zod.coerce.string(),
});

export const SetReviewedBody = zod.object({
  reviewed: zod.boolean(),
});

export const SetReviewedResponse = zod.object({
  reviewed: zod.boolean(),
});
